  ('heelevel3-53250add-moex-00305', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '公務員因作成或不作成行政處分，不法侵害人民權益者，請求國家賠償，下列何者錯誤？', '["於提起國家賠償前，原則上必須先進行行政爭訟請求救濟", "如行政爭訟程序已開始，民事法院無須停止國家賠償審判程序", "若人民於訴願期間向賠償義務機關表示不服請求協議賠償，致未依限提起訴願者，視為已遵期 提起訴願", "如行政法院判決已認行政處分不違法並予維持者，受理賠償訴訟之民事法院不得再自行審查行 政處分是否違法，而應以訴訟無理由駁回之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00306', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-cfe42432', 'sub-heelevel3-53250add-05', NULL, 'essay', '訴願法第 1條規定：「人民對中央或地方機關之行政處分，認為違法或不
當，致損害其權利或利益者。得依本法提起訴願，但法律另有規定者，
從其規定。」試附理由說明下列爭議是否屬於訴願救濟範圍？
財政部國有財產局或所屬分支機構，於人民依國有財產法第 52條之 2
規定申請讓售國有非公用財產類不動產之准駁決定。（25分）
都市計畫個別變更外的人民，因個別計畫變更導致權利或法律上利益
受侵害。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "01f614044d53", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0609", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "訴願法與行政訴訟法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
